PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE IF NOT EXISTS "authtoken_token" ("key" varchar(40) NOT NULL PRIMARY KEY, "created" datetime NOT NULL, "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_cctvdevice" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(200) NOT NULL, "domain" varchar(100) NOT NULL, "port" integer unsigned NOT NULL CHECK ("port" >= 0), "username" varchar(100) NOT NULL, "password" varchar(255) NOT NULL, "protocol" varchar(10) NOT NULL, "connect" varchar(10) NOT NULL, "camera_count" integer unsigned NOT NULL CHECK ("camera_count" >= 0), "is_active" bool NOT NULL, "last_checked" datetime NULL, "status" varchar(20) NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "monitor_ispconnection" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL, "isp_type" varchar(20) NOT NULL, "gateway_ip" char(39) NOT NULL, "dns_servers" text NOT NULL, "bandwidth_mbps" integer NOT NULL, "primary_connection" bool NOT NULL, "enabled" bool NOT NULL, "created_at" datetime NOT NULL, "last_checked" datetime NULL);
CREATE TABLE IF NOT EXISTS "monitor_networkdevice" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(200) NOT NULL UNIQUE, "device_type" varchar(20) NOT NULL, "ip_address" char(39) NOT NULL, "mac_address" varchar(17) NULL, "vendor" varchar(100) NULL, "hostname" varchar(255) NULL, "os_fingerprint" varchar(100) NULL, "open_ports" text NOT NULL CHECK ((JSON_VALID("open_ports") OR "open_ports" IS NULL)), "first_seen" datetime NOT NULL, "last_seen" datetime NOT NULL, "is_active" bool NOT NULL, "auto_discovered" bool NOT NULL, "notes" text NULL, "network" varchar(100) NULL, "snmp_community" varchar(100) NOT NULL, "snmp_port" integer unsigned NOT NULL CHECK ("snmp_port" >= 0), "api_token" varchar(255) NULL, "enabled" bool NOT NULL, "created_at" datetime NOT NULL, "last_checked" datetime NULL, "api_username" varchar(100) NULL, "api_port" integer unsigned NOT NULL CHECK ("api_port" >= 0));
CREATE TABLE IF NOT EXISTS "monitor_alertrule" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(200) NOT NULL, "enabled" bool NOT NULL, "kind" varchar(50) NOT NULL, "severity" varchar(10) NOT NULL, "threshold" real NULL, "duration_seconds" integer NOT NULL, "tags_filter" varchar(500) NOT NULL, "pinned_only" bool NOT NULL, "notification_channels" text NOT NULL CHECK ((JSON_VALID("notification_channels") OR "notification_channels" IS NULL)), "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "monitor_ispfailover" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "failover_time" datetime NOT NULL, "recovery_time" datetime NULL, "reason" varchar(200) NOT NULL, "duration_minutes" integer NULL, "backup_isp_id" bigint NULL REFERENCES "monitor_ispconnection" ("id") DEFERRABLE INITIALLY DEFERRED, "primary_isp_id" bigint NOT NULL REFERENCES "monitor_ispconnection" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_networkinterface" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL, "description" varchar(200) NOT NULL, "status" varchar(20) NOT NULL, "speed" integer NULL, "mtu" integer NULL, "username" varchar(50) NOT NULL, "password" varchar(50) NOT NULL, "device_id" bigint NOT NULL REFERENCES "monitor_networkdevice" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_checkresult" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "checked_at" datetime NOT NULL, "status" varchar(10) NOT NULL, "http_ok" bool NULL, "latency_ms" integer unsigned NULL CHECK ("latency_ms" >= 0), "http_status_code" integer unsigned NULL CHECK ("http_status_code" >= 0), "error" text NOT NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_servermetricsconfig" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "enable_cpu_monitoring" bool NOT NULL, "enable_ram_monitoring" bool NOT NULL, "enable_disk_monitoring" bool NOT NULL, "enable_ssl_monitoring" bool NOT NULL, "cpu_threshold_warning" real NOT NULL, "cpu_threshold_critical" real NOT NULL, "ram_threshold_warning" real NOT NULL, "ram_threshold_critical" real NOT NULL, "disk_threshold_warning" real NOT NULL, "disk_threshold_critical" real NOT NULL, "ssl_warning_days" integer NOT NULL, "ssl_critical_days" integer NOT NULL, "monitoring_interval" integer NOT NULL, "is_active" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "server_id" bigint NOT NULL UNIQUE REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_sshcredential" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "username" varchar(100) NOT NULL, "encrypted_password" text NOT NULL, "port" integer NOT NULL, "private_key_path" varchar(500) NULL, "is_active" bool NOT NULL, "last_tested" datetime NULL, "test_status" varchar(20) NOT NULL, "test_message" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "server_id" bigint NOT NULL UNIQUE REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_ispmetric" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "metric_name" varchar(100) NOT NULL, "value" real NOT NULL, "unit" varchar(20) NOT NULL, "timestamp" datetime NOT NULL, "connection_id" bigint NOT NULL REFERENCES "monitor_ispconnection" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_devicebandwidthusage" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "source_ip" char(39) NOT NULL, "dest_ip" char(39) NOT NULL, "bytes_sent" bigint NOT NULL, "bytes_received" bigint NOT NULL, "packets_sent" integer NOT NULL, "packets_received" integer NOT NULL, "connections" integer NOT NULL, "protocols" text NOT NULL CHECK ((JSON_VALID("protocols") OR "protocols" IS NULL)), "first_seen" datetime NOT NULL, "last_seen" datetime NOT NULL, "device_id" bigint NOT NULL REFERENCES "monitor_networkdevice" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_devicebandwidthmeasurement" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "interface" varchar(100) NULL, "bytes_in" bigint NOT NULL, "bytes_out" bigint NOT NULL, "packets_in" bigint NOT NULL, "packets_out" bigint NOT NULL, "bps_in" real NOT NULL, "bps_out" real NOT NULL, "pps_in" real NOT NULL, "pps_out" real NOT NULL, "measurement_method" varchar(20) NOT NULL, "timestamp" datetime NOT NULL, "device_id" bigint NOT NULL REFERENCES "monitor_networkdevice" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_networkmetric" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "metric_name" varchar(100) NOT NULL, "value" real NOT NULL, "unit" varchar(20) NOT NULL, "timestamp" datetime NOT NULL, "device_id" bigint NOT NULL REFERENCES "monitor_networkdevice" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_securityevent" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "event_type" varchar(100) NOT NULL, "source_ip" char(39) NULL, "dest_ip" char(39) NULL, "source_port" integer NULL, "dest_port" integer NULL, "protocol" varchar(10) NOT NULL, "action" varchar(20) NOT NULL, "rule_name" varchar(200) NOT NULL, "timestamp" datetime NOT NULL, "severity" varchar(20) NOT NULL, "device_id" bigint NOT NULL REFERENCES "monitor_networkdevice" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_resourcesample" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "collected_at" datetime NOT NULL, "cpu_percent" real NULL, "load_1" real NULL, "load_5" real NULL, "load_15" real NULL, "ram_total_bytes" bigint NULL, "ram_used_bytes" bigint NULL, "ram_percent" real NULL, "boot_time" datetime NULL, "uptime_seconds" bigint NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_rebootevent" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "boot_time" datetime NOT NULL, "detected_at" datetime NOT NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_networksample" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "collected_at" datetime NOT NULL, "bytes_sent" bigint NULL, "bytes_recv" bigint NULL, "packets_sent" bigint NULL, "packets_recv" bigint NULL, "errin" bigint NULL, "errout" bigint NULL, "dropin" bigint NULL, "dropout" bigint NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_diskusagesample" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "collected_at" datetime NOT NULL, "mount" varchar(200) NOT NULL, "fstype" varchar(64) NOT NULL, "total_bytes" bigint NULL, "used_bytes" bigint NULL, "percent" real NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_diskiosample" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "collected_at" datetime NOT NULL, "read_bytes" bigint NULL, "write_bytes" bigint NULL, "read_time_ms" bigint NULL, "write_time_ms" bigint NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_dbsample" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "collected_at" datetime NOT NULL, "engine" varchar(20) NOT NULL, "process_up" bool NULL, "port_ok" bool NULL, "port_ms" real NULL, "connect_ok" bool NULL, "ping_ms" real NULL, "current_connections" integer NULL, "max_connections" integer NULL, "connection_usage_percent" real NULL, "qps" real NULL, "read_qps" real NULL, "write_qps" real NULL, "tps" real NULL, "avg_query_ms" real NULL, "p95_query_ms" real NULL, "p99_query_ms" real NULL, "slow_queries_1m" integer NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_alertstate" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "is_active" bool NOT NULL, "pending_since" datetime NULL, "active_since" datetime NULL, "last_seen_at" datetime NULL, "rule_id" bigint NOT NULL REFERENCES "monitor_alertrule" ("id") DEFERRABLE INITIALLY DEFERRED, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_servermetrics" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "timestamp" datetime NOT NULL, "agent_server_id" varchar(255) NOT NULL, "cpu_percent" real NULL, "cpu_count" integer NULL, "load_1m" real NULL, "load_5m" real NULL, "load_15m" real NULL, "memory_total" bigint NULL, "memory_used" bigint NULL, "memory_percent" real NULL, "disk_total" bigint NULL, "disk_used" bigint NULL, "disk_percent" real NULL, "network_bytes_sent" bigint NULL, "network_bytes_recv" bigint NULL, "network_packets_sent" bigint NULL, "network_packets_recv" bigint NULL, "uptime_seconds" bigint NULL, "process_count" integer NULL, "hostname" varchar(255) NULL, "directory_metrics" text NULL CHECK ((JSON_VALID("directory_metrics") OR "directory_metrics" IS NULL)), "created_at" datetime NOT NULL, "server_id" bigint NOT NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_trafficlog" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "bytes_in" integer NOT NULL, "bytes_out" integer NOT NULL, "packets_in" integer NOT NULL, "packets_out" integer NOT NULL, "errors_in" integer NOT NULL, "errors_out" integer NOT NULL, "timestamp" datetime NOT NULL, "interface_id" bigint NOT NULL REFERENCES "monitor_networkinterface" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "monitor_sslcertificate" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(200) NOT NULL, "domain" varchar(255) NOT NULL, "alternative_names" text NOT NULL CHECK ((JSON_VALID("alternative_names") OR "alternative_names" IS NULL)), "serial_number" varchar(100) NULL, "key_type" varchar(20) NOT NULL, "issuer" varchar(500) NULL, "subject" varchar(500) NULL, "cert_path" varchar(500) NULL, "key_path" varchar(500) NULL, "issued_at" datetime NULL, "expires_at" datetime NULL, "is_valid" bool NOT NULL, "is_self_signed" bool NOT NULL, "days_until_expiry" integer NULL, "enabled" bool NOT NULL, "last_checked" datetime NULL, "check_frequency" integer NOT NULL, "warning_days" integer NOT NULL, "critical_days" integer NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "server_id" bigint NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_alertevent" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "created_at" datetime NOT NULL, "kind" varchar(50) NOT NULL, "severity" varchar(10) NOT NULL, "is_recovery" bool NOT NULL, "title" varchar(200) NOT NULL, "message" text NOT NULL, "value" real NULL, "payload" text NOT NULL CHECK ((JSON_VALID("payload") OR "payload" IS NULL)), "rule_id" bigint NULL REFERENCES "monitor_alertrule" ("id") DEFERRABLE INITIALLY DEFERRED, "server_id" bigint NULL REFERENCES "monitor_server" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "monitor_server" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(200) NOT NULL UNIQUE, "server_type" varchar(20) NOT NULL, "ip_address" char(39) NOT NULL, "port" integer unsigned NOT NULL CHECK ("port" >= 0), "use_https" bool NOT NULL, "path" varchar(200) NOT NULL, "http_check" bool NOT NULL, "enabled" bool NOT NULL, "pinned" bool NOT NULL, "tags" varchar(500) NOT NULL, "last_status" varchar(10) NOT NULL, "last_http_ok" bool NULL, "skip_ssl_verification" bool NOT NULL, "last_checked" datetime NULL, "last_latency_ms" integer unsigned NULL CHECK ("last_latency_ms" >= 0), "last_http_status_code" integer unsigned NULL CHECK ("last_http_status_code" >= 0), "last_error" text NOT NULL, "last_resource_checked" datetime NULL, "last_cpu_percent" real NULL, "last_ram_percent" real NULL, "last_disk_percent" real NULL, "last_load_1" real NULL, "last_uptime_seconds" bigint NULL, "last_boot_time" datetime NULL, "last_db_checked" datetime NULL, "last_db_process_up" bool NULL, "last_db_port_ok" bool NULL, "last_db_connect_ok" bool NULL, "last_db_ping_ms" real NULL, "last_db_connections" integer NULL, "last_db_max_connections" integer NULL, "last_db_conn_usage_percent" real NULL, "last_db_qps" real NULL, "last_db_read_qps" real NULL, "last_db_write_qps" real NULL, "last_db_tps" real NULL, "last_db_avg_query_ms" real NULL, "last_db_p95_query_ms" real NULL, "last_db_p99_query_ms" real NULL, "last_db_slow_1m" integer NULL, "agent_status" varchar(20) NOT NULL, "agent_version" varchar(50) NULL, "last_agent_heartbeat" datetime NULL, "last_agent_metrics" datetime NULL, "agent_token" varchar(255) NULL UNIQUE, "monitored_directories" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "ssl_cert_path" varchar(500) NOT NULL);
CREATE TABLE IF NOT EXISTS "projects_management_project" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL UNIQUE, "repo_url" varchar(500) NOT NULL, "github_token" varchar(500) NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "projects_management_server" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "hostname" varchar(255) NOT NULL, "user" varchar(255) NOT NULL, "password" varchar(500) NOT NULL, "path" varchar(500) NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "project_id" bigint NOT NULL REFERENCES "projects_management_project" ("id") DEFERRABLE INITIALLY DEFERRED);
